# scripts/prompt_lint.py — CI prompt linter
import re
import sys
import tiktoken
from pathlib import Path

MAX_TOKENS = 4096
STYLE_RULES = [
    (r'\[INSERT \w+\]', 'Unfilled template placeholder detected'),
    (r'ignore previous instructions', 'Injection-susceptible phrase detected'),
    (r'you can ignore', 'Instruction override language detected'),
]

def count_tokens(text: str) -> int:
    enc = tiktoken.get_encoding('cl100k_base')
    return len(enc.encode(text))

def lint_prompt(path: Path) -> list[str]:
    text = path.read_text(encoding='utf-8')
    errors = []
    token_count = count_tokens(text)
    if token_count > MAX_TOKENS:
        errors.append(f'Token count {token_count} exceeds limit {MAX_TOKENS}')
    for pattern, message in STYLE_RULES:
        if re.search(pattern, text, re.IGNORECASE):
            errors.append(f'{message}: matched pattern "{pattern}"')
    return errors

if __name__ == '__main__':
    failed = False
    for filepath in sys.argv[1:]:
        p = Path(filepath)
        errs = lint_prompt(p)
        if errs:
            failed = True
            for e in errs:
                print(f'ERROR [{p}]: {e}')
        else:
            print(f'OK [{p}]')
    sys.exit(1 if failed else 0)
